TRANS["hero-variant-1"] = {en: "Access the world's most sophisticated AI models through a single, elegant API. Designed for those who demand excellence.", "zh-CN": "通过一个优雅的 API 访问全球最尖端的 AI 模型。为追求卓越者而生。", ru: "Получите доступ к самым совершенным моделям ИИ через единый элегантный API. Создано для тех, кто стремится к совершенству.", ja: "世界で最も洗練されたAIモデルに、一つの洗練されたAPIでアクセス。卓越性を求める方のために。", de: "Greifen Sie über eine einzige, elegante API auf die anspruchsvollsten KI-Modelle der Welt zu. Entwickelt für diejenigen, die Exzellenz fordern."};
TRANS["hero-variant-2"] = {en: "Unlock the full spectrum of AI through one unified API. Premium models, one balance, limitless potential.", "zh-CN": "通过一个统一的 API 解锁 AI 的全光谱。优质模型，一个余额，无限潜力。", ru: "Откройте полный спектр ИИ через один унифицированный API. Премиум-модели, один баланс, безграничный потенциал.", ja: "一つの統合APIでAIの全領域を解放。プレミアムモデル、一つの残高、無限の可能性。", de: "Entfesseln Sie das gesamte Spektrum der KI über eine einzige, einheitliche API. Premium-Modelle, ein Guthaben, grenzenloses Potenzial."};
TRANS["hero-variant-3"] = {en: "Your gateway to 100+ premium AI models. One API key, one balance, zero complexity.", "zh-CN": "通往 100+ 优质 AI 模型的门户。一个 API 密钥，一个余额，零复杂度。", ru: "Ваш шлюз к 100+ премиальным моделям ИИ. Один API-ключ, один баланс, ноль сложности.", ja: "100以上のプレミアムAIモデルへのゲートウェイ。一つのAPIキー、一つの残高、複雑さゼロ。", de: "Ihr Gateway zu 100+ Premium-KI-Modellen. Ein API-Schlüssel, ein Guthaben, null Komplexität."};
TRANS["hero-variant-4"] = {en: "Every AI model at your fingertips. One elegant API, one token balance, infinite possibilities.", "zh-CN": "所有 AI 模型尽在指尖。一个优雅的 API，一个通证余额，无限可能。", ru: "Все модели ИИ у вас под рукой. Один элегантный API, один баланс токенов, бесконечные возможности.", ja: "あらゆるAIモデルを指先に。一つの洗練されたAPI、一つのトークン残高、無限の可能性。", de: "Jedes KI-Modell zur Hand. Eine elegante API, ein Token-Guthaben, unendliche Möglichkeiten."};
TRANS["hero-variant-5"] = {en: "The most advanced AI models, unified under a single API. Built for builders who demand the best.", "zh-CN": "最先进的 AI 模型，统一于一个 API 之下。为追求卓越的构建者而生。", ru: "Самые передовые модели ИИ, объединённые под единым API. Создано для разработчиков, которые требуют лучшего.", ja: "最先端のAIモデルを単一のAPIで統合。最高を求めるビルダーのために。", de: "Die fortschrittlichsten KI-Modelle, vereint unter einer einzigen API. Entwickelt für Entwickler, das Beste verlangen."};
TRANS["hero-variant-6"] = {en: "Access a vast selection of models through one standard, unified API protocol. Power your AI apps, manage digital assets, and connect to the future.", "zh-CN": "通过一个标准、统一的 API 协议访问海量模型。赋能 AI 应用，管理数字资产，连接未来。", ru: "Получите доступ к огромному выбору моделей через один стандартный, унифицированный протокол API. Питайте свои ИИ-приложения, управляйте цифровыми активами и подключайтесь к будущему.", ja: "標準化された統一APIプロトコルを通じて、豊富なモデルにアクセス。AIアプリを強化し、デジタル資産を管理し、未来へつなぐ。", de: "Greifen Sie über ein standardisiertes, einheitliches API-Protokoll auf eine große Auswahl an Modellen zu. Betreiben Sie Ihre KI-Apps, verwalten Sie digitale Assets und verbinden Sie sich mit der Zukunft."};

I18N_MIXED["footer-tagline"] = {en: "Global Token for AI. One balance, 100+ models, 56 providers. Pay-as-you-go.", "zh-CN": "AI 全球通证。一个余额，100+ 模型，56 家供应商。按需付费。", ru: "Глобальный токен для ИИ. Один баланс, 100+ моделей, 56 провайдеров. Оплата по мере использования.", ja: "AIのためのグローバルトークン。1つの残高、100以上のモデル、56のプロバイダー。従量課金制。", de: "Globaler Token für KI. Ein Guthaben, 100+ Modelle, 56 Anbieter. Pay-as-you-go."};
I18N_MIXED["footer-email-label"] = {en: "<strong>Email</strong>", "zh-CN": "<strong>\u90ae\u7bb1</strong>", ru: "<strong>Email</strong>", ja: "<strong>\u30e1\u30fc\u30eb</strong>", de: "<strong>E-Mail</strong>"};

I18N_MIXED["blog-1"] = {en: "We're excited to launch GlbTOKEN, the unified token for accessing 100+ AI models. No more juggling subscriptions \u2014 one balance, one API, unlimited AI.", "zh-CN": "\u6211\u4eec\u6fc0\u52a8\u5730\u5ba3\u5e03 GlbTOKEN \u7684\u53d1\u5e03\uff0c\u8fd9\u662f\u7edf\u4e00\u7684 AI \u6a21\u578b\u8bbf\u95ee\u4ee3\u5e01\u3002\u4e0d\u518d\u9700\u8981\u7ba1\u7406\u591a\u4e2a\u8ba2\u9605 \u2014 \u4e00\u4e2a\u4f59\u989d\uff0c\u4e00\u4e2a API\uff0c\u65e0\u9650 AI\u3002", ru: "\u041c\u044b \u0440\u0430\u0434\u044b \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u0442\u044c GlbTOKEN, \u0435\u0434\u0438\u043d\u044b\u0439 \u0442\u043e\u043a\u0435\u043d \u0434\u043e\u0441\u0442\u0443\u043f\u0430 \u043a 100+ \u043c\u043e\u0434\u0435\u043b\u044f\u043c \u0418\u0418. \u0411\u043e\u043b\u044c\u0448\u0435 \u043d\u0438\u043a\u0430\u043a\u0438\u0445 \u043f\u043e\u0434\u043f\u0438\u0441\u043e\u043a \u2014 \u043e\u0434\u0438\u043d \u0431\u0430\u043b\u0430\u043d\u0441, \u043e\u0434\u0438\u043d API, \u043d\u0435\u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0435\u043d\u043d\u044b\u0439 \u0418\u0418.", ja: "GlbTOKEN\u306e\u30ed\u30fc\u30f3\u30c1\u3092\u767a\u8868\u3067\u304d\u308b\u3053\u3068\u3092\u8ca0\u3044\u306b\u601d\u3044\u307e\u3059\u3002100\u4ee5\u4e0a\u306eAI\u30e2\u30c7\u30eb\u306b\u30a2\u30af\u30bb\u30b9\u3067\u304d\u308b\u7d71\u5408\u30c8\u30fc\u30af\u30f3\u3067\u3059\u3002\u30b5\u30d6\u30b9\u30af\u30ea\u30d7\u30b7\u30e7\u30f3\u306e\u7ba1\u7406\u306f\u3082\u3046\u5fc5\u8981\u3042\u308a\u307e\u305b\u3093 \u2014 1\u3064\u306e\u6b8b\u9ad8\u30011\u3064\u306eAPI\u3001\u9650\u308a\u306a\u304fAI\u3092\u4f7f\u7528\u3067\u304d\u307e\u3059\u3002", de: "Wir freuen uns, GlbTOKEN anzuk\u00fcndigen, den einheitlichen Token f\u00fcr den Zugriff auf 100+ KI-Modelle. Keine Abos mehr \u2014 ein Guthaben, eine API, unbegrenzte KI."};
I18N_MIXED["blog-2"] = {en: "We've added the latest flagship models from OpenAI and Anthropic. GPT-5.5 Pro and Claude Sonnet 5 are now available through the GlbTOKEN API.", "zh-CN": "\u6211\u4eec\u65b0\u589e\u4e86 OpenAI \u548c Anthropic \u7684\u6700\u65b0\u65d7\u8230\u6a21\u578b\u3002GPT-5.5 Pro \u548c Claude Sonnet 5 \u73b0\u5df2\u901a\u8fc7 GlbTOKEN API \u63d0\u4f9b\u3002", ru: "\u041c\u044b \u0434\u043e\u0431\u0430\u0432\u0438\u043b\u0438 \u043d\u043e\u0432\u0435\u0439\u0448\u0438\u0435 \u0444\u043b\u0430\u0433\u043c\u0430\u043d\u0441\u043a\u0438\u0435 \u043c\u043e\u0434\u0435\u043b\u0438 \u043e\u0442 OpenAI \u0438 Anthropic. GPT-5.5 Pro \u0438 Claude Sonnet 5 \u0442\u0435\u043f\u0435\u0440\u044c \u0434\u043e\u0441\u0442\u0443\u043f\u043d\u044b \u0447\u0435\u0440\u0435\u0437 GlbTOKEN API.", ja: "OpenAI\u3068Anthropic\u304b\u3089\u6700\u65b0\u306e\u30d5\u30e9\u30c3\u30b0\u30b7\u30c3\u30d7\u30e2\u30c7\u30eb\u3092\u8ffd\u52a0\u3057\u307e\u3057\u305f\u3002GPT-5.5 Pro\u3068Claude Sonnet 5\u304cGlbTOKEN API\u3067\u5229\u7528\u53ef\u80fd\u306b\u306a\u308a\u307e\u3057\u305f\u3002", de: "Wir haben die neuesten Flaggschiff-Modelle von OpenAI und Anthropic hinzugef\u00fcgt. GPT-5.5 Pro und Claude Sonnet 5 sind jetzt \u00fcber die GlbTOKEN API verf\u00fcgbar."};
I18N_MIXED["blog-3"] = {en: "Users in Ghana, Nigeria, Kenya, and South Africa can now pay with local currencies via Paystack. Bank transfer, USSD, and mobile money supported.", "zh-CN": "\u52a0\u7eb3\u3001\u5c3c\u65e5\u5229\u4e9a\u3001\u80af\u5c3c\u4e9a\u548c\u5357\u975e\u7684\u7528\u6237\u73b0\u53ef\u901a\u8fc7 Paystack \u4f7f\u7528\u5f53\u5730\u8d27\u5e01\u652f\u4ed8\u3002\u652f\u6301\u94f6\u884c\u8f6c\u8d26\u3001USSD \u548c\u79fb\u52a8\u652f\u4ed8\u3002", ru: "\u041f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u0435\u043b\u0438 \u0432 \u0413\u0430\u043d\u0435, \u041d\u0438\u0433\u0435\u0440\u0438\u0438, \u041a\u0435\u043d\u0438\u0438 \u0438 \u042e\u0410\u0420 \u0442\u0435\u043f\u0435\u0440\u044c \u043c\u043e\u0433\u0443\u0442 \u043f\u043b\u0430\u0442\u0438\u0442\u044c \u0432 \u043c\u0435\u0441\u0442\u043d\u043e\u0439 \u0432\u0430\u043b\u044e\u0442\u0435 \u0447\u0435\u0440\u0435\u0437 Paystack. \u041f\u043e\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044e\u0442\u0441\u044f \u0431\u0430\u043d\u043a\u043e\u0432\u0441\u043a\u0438\u0435 \u043f\u0435\u0440\u0435\u0432\u043e\u0434\u044b, USSD \u0438 \u043c\u043e\u0431\u0438\u043b\u044c\u043d\u044b\u0435 \u0434\u0435\u043d\u044c\u0433\u0438.", ja: "\u30ac\u30fc\u30ca\u3001\u30ca\u30a4\u30b8\u30a7\u30ea\u30a2\u3001\u30b1\u30cb\u30a2\u3001\u5357\u30a2\u30d5\u30ea\u30ab\u306e\u30e6\u30fc\u30b6\u30fc\u306f\u3001Paystack\u3092\u901a\u3058\u3066\u5730\u5143\u901a\u8ca8\u3067\u652f\u6255\u3044\u304c\u3067\u304d\u308b\u3088\u3046\u306b\u306a\u308a\u307e\u3057\u305f\u3002\u9280\u884c\u632f\u8fbc\u3001USSD\u3001\u30e2\u30d0\u30a4\u30eb\u30de\u30cd\u30fc\u306b\u5bfe\u5fdc\u3002", de: "Nutzer in Ghana, Nigeria, Kenia und S\u00fcdafrika k\u00f6nnen jetzt mit lokalen W\u00e4hrungen \u00fcber Paystack bezahlen. Bank\u00fcberweisung, USSD und Mobile Money werden unterst\u00fctzt."};
I18N_MIXED["blog-4"] = {en: "Our OpenAI-compatible API is now live. Generate a key and start building with any model in minutes. Full documentation in the Developer section.", "zh-CN": "\u6211\u4eec\u7684 OpenAI \u517c\u5bb9 API \u5df2\u7ecf\u4e0a\u7ebf\u3002\u751f\u6210\u5bc6\u94a5\uff0c\u5373\u53ef\u5728\u51e0\u5206\u949f\u5185\u5f00\u59cb\u4f7f\u7528\u4efb\u4f55\u6a21\u578b\u6784\u5efa\u3002\u5b8c\u6574\u6587\u6863\u5728\u5f00\u53d1\u8005\u6a21\u5757\u4e2d\u3002", ru: "\u041d\u0430\u0448 OpenAI-\u0441\u043e\u0432\u043c\u0435\u0441\u0442\u0438\u043c\u044b\u0439 API \u0443\u0436\u0435 \u0437\u0430\u043f\u0443\u0449\u0435\u043d. \u0421\u043e\u0437\u0434\u0430\u0439\u0442\u0435 \u043a\u043b\u044e\u0447 \u0438 \u043d\u0430\u0447\u0438\u043d\u0430\u0439\u0442\u0435 \u0440\u0430\u0431\u043e\u0442\u0430\u0442\u044c \u0441 \u043b\u044e\u0431\u043e\u0439 \u043c\u043e\u0434\u0435\u043b\u044c\u044e \u0437\u0430 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043c\u0438\u043d\u0443\u0442. \u041f\u043e\u043b\u043d\u0430\u044f \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u0430\u0446\u0438\u044f \u0432 \u0440\u0430\u0437\u0434\u0435\u043b\u0435 \u0434\u043b\u044f \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u0447\u0438\u043a\u043e\u0432.", ja: "OpenAI\u4e92\u63dbAPI\u304c\u30ea\u30ea\u30fc\u30b9\u3055\u308c\u307e\u3057\u305f\u3002\u30ad\u30fc\u3092\u751f\u6210\u3057\u3066\u3001\u6570\u5206\u3067\u3042\u3089\u3086\u308b\u30e2\u30c7\u30eb\u3067\u69cb\u7bc9\u3092\u59cb\u3081\u3089\u308c\u307e\u3059\u3002\u8a73\u7d30\u306f\u30c7\u30d9\u30ed\u30c3\u30d1\u30fc\u30bb\u30af\u30b7\u30e7\u30f3\u306e\u30c9\u30ad\u30e5\u30e1\u30f3\u30c8\u3092\u3054\u89a7\u304f\u3060\u3055\u3044\u3002", de: "Unsere OpenAI-kompatible API ist jetzt live. Generieren Sie einen Schl\u00fcssel und beginnen Sie in Minuten mit jedem Modell zu bauen. Vollst\u00e4ndige Dokumentation im Entwicklerbereich."};

I18N_MIXED["blog-5-title"] = {en: "Security Update: SOC 2 Compliance & Encryption", "zh-CN": "安全更新：SOC 2 合规性与加密", ru: "Обновление безопасности: соответствие SOC 2 и шифрование", ja: "セキュリティアップデート：SOC 2 コンプライアンスと暗号化", de: "Sicherheitsupdate: SOC 2-Compliance & Verschlüsselung"};
I18N_MIXED["blog-5-date"] = {en: "June 20, 2026", "zh-CN": "June 20, 2026", ru: "June 20, 2026", ja: "June 20, 2026", de: "June 20, 2026"};
I18N_MIXED["blog-5"] = {en: "We've completed SOC 2 Type II certification. All API traffic is now encrypted end-to-end, and user data is isolated at the database level. Enterprise customers can request a security whitepaper.", "zh-CN": "我们已完成 SOC 2 Type II 认证。所有 API 流量现已实现端到端加密，用户数据在数据库级别隔离。企业客户可申请安全白皮书。", ru: "Мы завершили сертификацию SOC 2 Type II. Весь API-трафик теперь зашифрован сквозным шифрованием, а данные пользователей изолированы на уровне базы данных. Корпоративные клиенты могут запросить технический документ по безопасности.", ja: "SOC 2 Type II 認証を完了しました。すべてのAPIトラフィックはエンドツーエンドで暗号化され、ユーザーデータはデータベースレベルで隔離されています。エンタープライズのお客様はセキュリティホワイトペーパーを請求いただけます。", de: "Wir haben die SOC 2 Type II-Zertifizierung abgeschlossen. Der gesamte API-Verkehr ist jetzt Ende-zu-Ende verschlüsselt und Benutzerdaten werden auf Datenbankebene isoliert. Unternehmenskunden können ein Sicherheits-Whitepaper anfordern."};
I18N_MIXED["blog-6-title"] = {en: "Mobile App Beta: Manage Your Balance on the Go", "zh-CN": "移动应用测试版：随时随地管理您的余额", ru: "Бета-версия мобильного приложения: управляйте балансом на ходу", ja: "モバイルアプリベータ版：外出先でも残高管理", de: "Mobile App Beta: Verwalten Sie Ihr Guthaben unterwegs"};
I18N_MIXED["blog-6-date"] = {en: "June 15, 2026", "zh-CN": "June 15, 2026", ru: "June 15, 2026", ja: "June 15, 2026", de: "June 15, 2026"};
I18N_MIXED["blog-6"] = {en: "Our mobile web app is now in beta — optimized for mobile browsers with a full dashboard, buy tokens, and support chat. No app store download needed.", "zh-CN": "我们的移动网页应用现已推出测试版 — 针对移动浏览器优化，包含完整仪表盘、购买代币和支持聊天。无需下载应用商店。", ru: "Наше мобильное веб-приложение теперь в бета-версии — оптимизировано для мобильных браузеров с полной панелью управления, покупкой токенов и чатом поддержки. Загрузка из магазина приложений не требуется.", ja: "モバイルウェブアプリがベータ版になりました — モバイルブラウザに最適化され、完全なダッシュボード、トークン購入、サポートチャットを備えています。アプリストアからのダウンロードは不要です。", de: "Unsere mobile Web-App ist jetzt in der Beta-Phase — optimiert für mobile Browser mit vollständigem Dashboard, Token-Kauf und Support-Chat. Kein App-Store-Download erforderlich."};
I18N_MIXED["blog-1-title"] = {en: "Introducing GlbTOKEN — One Balance for All AI", "zh-CN": "GlbTOKEN 正式发布 — 一个余额畅享所有 AI", ru: "Представляем GlbTOKEN — один баланс для всех ИИ", ja: "GlbTOKEN のご紹介 — すべてのAIに一つの残高", de: "Einführung von GlbTOKEN — Ein Guthaben für alle KI"};
